import{_ as a,c as e,a1 as s,o as t}from"./chunks/framework.BDxlaA_J.js";const g=JSON.parse('{"title":"Các kiến thức cơ bản về Footprinting với dòng lệnh Windows","description":"","frontmatter":{},"headers":[],"relativePath":"vi/categories/ethical-hacking-labs/1-footprinting-and-reconnaissance/1-Windows-CommandLine.md","filePath":"vi/categories/ethical-hacking-labs/1-footprinting-and-reconnaissance/1-Windows-CommandLine.md"}'),i={name:"vi/categories/ethical-hacking-labs/1-footprinting-and-reconnaissance/1-Windows-CommandLine.md"};function c(p,n,o,r,h,l){return t(),e("div",null,n[0]||(n[0]=[s(`<h1 id="cac-kien-thuc-co-ban-ve-footprinting-voi-dong-lenh-windows" tabindex="-1">Các kiến thức cơ bản về Footprinting với dòng lệnh Windows <a class="header-anchor" href="#cac-kien-thuc-co-ban-ve-footprinting-voi-dong-lenh-windows" aria-label="Permalink to &quot;Các kiến thức cơ bản về Footprinting với dòng lệnh Windows&quot;">​</a></h1><p>Mục tiêu của hướng dẫn này là dạy các kiến thức cơ bản về phương pháp Footprinting, được sử dụng cho các ethical-hacker và pentester.</p><h3 id="yeu-cau" tabindex="-1">Yêu cầu <a class="header-anchor" href="#yeu-cau" aria-label="Permalink to &quot;Yêu cầu&quot;">​</a></h3><ul><li>Môi trường ảo</li><li>Windows 8.1/10</li><li>Windows Server 2012 hoặc 2016</li><li>Kiến thức cơ bản về mạng</li></ul><h3 id="muc-tieu" tabindex="-1">Mục tiêu <a class="header-anchor" href="#muc-tieu" aria-label="Permalink to &quot;Mục tiêu&quot;">​</a></h3><ul><li>Sử dụng lệnh ping để tìm địa chỉ IP của tên miền mục tiêu.</li><li>Sử dụng lệnh ping để mô phỏng traceroute (lệnh tracert).</li><li>Khám phá kích thước frame tối đa cho mạng.</li><li>Kiểu ICMP và mã cho gói echo request và echo reply.</li></ul><h2 id="cac-lenh-su-dung-trong-huong-dan-nay" tabindex="-1">Các lệnh sử dụng trong hướng dẫn này <a class="header-anchor" href="#cac-lenh-su-dung-trong-huong-dan-nay" aria-label="Permalink to &quot;Các lệnh sử dụng trong hướng dẫn này&quot;">​</a></h2><h2 id="ping" tabindex="-1"><code>ping</code> <a class="header-anchor" href="#ping" aria-label="Permalink to &quot;\`\`\`ping\`\`\`&quot;">​</a></h2><p>Lệnh ping gửi ICMP (Internet Control Message Protocol) Dùng để kiểm tra khả năng truy cập của một host trên mạng IP và đo thời gian truyền của các tin nhắn gửi từ host nguồn đến đích mục tiêu.</p><h2 id="nslookup" tabindex="-1"><code>nslookup</code> <a class="header-anchor" href="#nslookup" aria-label="Permalink to &quot;\`\`\`nslookup\`\`\`&quot;">​</a></h2><p>Dùng để truy vấn DNS (Domain Name System), để lấy ánh xạ tên miền hoặc địa chỉ IP và các bản ghi DNS cụ thể khác.</p><h2 id="tracert-windows-hoac-traceroute-linux" tabindex="-1"><code>tracert</code>) (Windows) hoặc <code>traceroute</code> (Linux) <a class="header-anchor" href="#tracert-windows-hoac-traceroute-linux" aria-label="Permalink to &quot;\`\`\`tracert\`\`\`) (Windows) hoặc \`\`\`traceroute\`\`\` (Linux)&quot;">​</a></h2><p>Công cụ chẩn đoán để hiển thị tuyến đường và đo độ trễ truyền tải của các gói tin qua mạng IP.</p><p><strong>LƯU Ý:</strong><strong>Tôi khuyến nghị bạn sử dụng lệnh -help để xem tất cả các tham số của một lệnh cụ thể</strong></p><p><code>ping -help</code></p><hr><h2 id="tim-đia-chi-ip-cua-http-www-certifiedhacker-com" tabindex="-1">Tìm địa chỉ IP của <a href="http://www.certifiedhacker.com" target="_blank" rel="noreferrer">http://www.certifiedhacker.com</a> <a class="header-anchor" href="#tim-đia-chi-ip-cua-http-www-certifiedhacker-com" aria-label="Permalink to &quot;Tìm địa chỉ IP của http://www.certifiedhacker.com&quot;">​</a></h2><p>Mở <strong>Command prompt</strong> hoặc <strong>PowerShell</strong> trên Windows và gõ:</p><p><code>ping www.certifiedhacker.com</code></p><p>Kết quả sẽ tương tự như thông báo dưới đây. Lưu ý: Địa chỉ IP có thể khác trong môi trường của bạn.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Reply from 162.241.216.11: bytes=32 time=160ms TTL=40</span></span>
<span class="line"><span>Reply from 162.241.216.11: bytes=32 time=151ms TTL=40</span></span>
<span class="line"><span>Reply from 162.241.216.11: bytes=32 time=151ms TTL=40</span></span>
<span class="line"><span>Reply from 162.241.216.11: bytes=32 time=153ms TTL=40</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Ping statistics for 162.241.216.11:</span></span>
<span class="line"><span>    Packets: Sent = 4, Received = 4, Lost = 0 (0% loss)</span></span>
<span class="line"><span>Approximate round trip times in milli-seconds:</span></span>
<span class="line"><span>    Minimum = 151ms, Maximum = 160ms, Average = 153ms</span></span></code></pre></div><hr><h2 id="tim-kich-thuoc-frame-toi-đa-tren-mang" tabindex="-1">Tìm kích thước frame tối đa trên mạng <a class="header-anchor" href="#tim-kich-thuoc-frame-toi-đa-tren-mang" aria-label="Permalink to &quot;Tìm kích thước frame tối đa trên mạng&quot;">​</a></h2><p>Sử dụng lệnh trước đó và thêm tham số <code>-f</code> để không phân mảnh gói ping và <code>-l</code> để đặt kích thước frame là <code>1500</code> byte.</p><p><code>ping www.certifiedhacker.com -f -l 1500</code></p><p>Kết quả:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Packet needs to be fragmented but DF set.</span></span></code></pre></div><p>Thông báo trên có nghĩa là frame quá lớn để truyền trên mạng và cần được phân mảnh.</p><p>Mục đích ở đây là thử các giá trị khác nhau cho đến khi bạn đạt được kích thước frame tối đa.</p><p><strong>Ví dụ:</strong></p><p><code> ping www.certifiedhacker.com -f -l 1450</code><em>hoạt động</em><code> ping www.certifiedhacker.com -f -l 1475</code><em>đã đạt giới hạn</em><code> ping www.certifiedhacker.com -f -l 1473</code><em>đã đạt giới hạn</em><code> ping www.certifiedhacker.com -f -l 1472</code><em>hoạt động</em></p><p>Tóm lại, lưu ý rằng hai kết quả cuối <code>1473</code> byte và <code>1472</code> byte cho thấy <strong>kích thước frame tối đa</strong> trên mạng của máy này.</p><hr><h2 id="khao-sat-ttl-time-to-live" tabindex="-1">Khảo sát TTL (Time to Live). <a class="header-anchor" href="#khao-sat-ttl-time-to-live" aria-label="Permalink to &quot;Khảo sát TTL (Time to Live).&quot;">​</a></h2><p>Mỗi frame trên mạng đều có TTL được xác định riêng. Nếu TTL đạt 0, router sẽ loại bỏ gói tin để tránh mất mát gói tin.</p><p><code>ping www.certifiedhacker.com -i 3</code></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Reply from 10.10.127.254: TTL expired in transit.</span></span>
<span class="line"><span>Reply from 10.10.127.254: TTL expired in transit.</span></span>
<span class="line"><span>Reply from 10.10.127.254: TTL expired in transit.</span></span>
<span class="line"><span>Reply from 10.10.127.254: TTL expired in transit.</span></span></code></pre></div><p>Tham số <code>-i</code> có nghĩa là thời gian chờ, tức là số giây chờ giữa mỗi lần ping (giá trị từ <code>1-255</code>).</p><p>TTL expired có nghĩa là router đã loại bỏ frame, vì TTL đã hết (đạt 0).</p><hr><h2 id="tim-traceroute-tu-may-cua-ban-đen-www-certifiedhacker-com" tabindex="-1">Tìm traceroute từ máy của bạn đến www.certifiedhacker.com <a class="header-anchor" href="#tim-traceroute-tu-may-cua-ban-đen-www-certifiedhacker-com" aria-label="Permalink to &quot;Tìm traceroute từ máy của bạn đến www.certifiedhacker.com&quot;">​</a></h2><p>Lệnh này thực hiện traceroute thông tin cấu hình mạng của tên miền mục tiêu.</p><p>Mở một cửa sổ mới trên prompt hoặc powershell và gõ:</p><p><code>tracert www.certifiedhacker.com</code></p><p>Hệ thống phân giải URL thành địa chỉ IP và bắt đầu dò đường đến đích. Ở đây gói tin cần 19 hop để đến được đích.</p><p>Bạn có thể sử dụng flag help để hiển thị các tùy chọn khác nhau cho lệnh: <code>tracert /?</code></p><hr><h2 id="hay-kiem-tra-tuoi-tho-cua-goi-tin" tabindex="-1">Hãy kiểm tra tuổi thọ của gói tin. <a class="header-anchor" href="#hay-kiem-tra-tuoi-tho-cua-goi-tin" aria-label="Permalink to &quot;Hãy kiểm tra tuổi thọ của gói tin.&quot;">​</a></h2><p>Mở một cửa sổ mới trên prompt hoặc powershell và gõ:</p><p><code>ping www.certifiedhacker.com -i 2 -n 1</code></p><p>Chúng ta đang đặt TTL là <code>2</code> trong nỗ lực kiểm tra tuổi thọ của gói tin và <code>-n</code> số lượng gói tin là <code>1</code></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Pinging certifiedhacker.com [162.241.216.11] with 32 bytes of data:</span></span>
<span class="line"><span>Reply from 10.10.10.45: TTL expired in transit.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Ping statistics for 162.241.216.11:</span></span>
<span class="line"><span>    Packets: Sent = 1, Received = 1, Lost = 0 (0% loss),</span></span></code></pre></div><p>Có một phản hồi đến từ địa chỉ IP 162.241.216.11 mà không mất gói tin.</p><p>Hãy đặt giá trị TTL là <code>3</code> để xem điều gì xảy ra</p><p><code>ping www.certifiedhacker.com -i 3 -n 1</code></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Pinging certifiedhacker.com [162.241.216.11] with 32 bytes of data:</span></span>
<span class="line"><span>Reply from 10.10.127.254: TTL expired in transit.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Ping statistics for 162.241.216.11:</span></span>
<span class="line"><span>    Packets: Sent = 1, Received = 1, Lost = 0 (0% loss),</span></span></code></pre></div><p>Lưu ý có một địa chỉ IP khác, giống với địa chỉ mà chúng ta thu được ở lệnh traceroute ở các hop đầu tiên.</p><p>Lặp lại thao tác này và tăng giá trị TTL cho đến khi đạt được địa chỉ IP của www.certifiedhacker.com mà chúng ta đã traceroute trước đó.</p><p><code>ping www.certifiedhacker.com -i 19 -n 1</code></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Pinging certifiedhacker.com [162.241.216.11] with 32 bytes of data:</span></span>
<span class="line"><span>Reply from 162.241.216.11: bytes=32 time=156ms TTL=40</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Ping statistics for 162.241.216.11:</span></span>
<span class="line"><span>    Packets: Sent = 1, Received = 1, Lost = 0 (0% loss),</span></span>
<span class="line"><span>Approximate round trip times in milli-seconds:</span></span>
<span class="line"><span>    Minimum = 156ms, Maximum = 156ms, Average = 156ms</span></span></code></pre></div><p>Xong! Những kết quả này ngụ ý rằng khi bạn đặt TTL là 19 (trong trường hợp này) thì phản hồi được nhận từ host đích (162.241.216.11). Hãy lưu ý rằng kết quả sẽ tương tự như kết quả traceroute.</p><p>Ghi lại tất cả các địa chỉ IP mà bạn nhận được phản hồi.</p><hr><h2 id="su-dung-lenh-nslookup" tabindex="-1">Sử dụng lệnh <code>nslookup</code> <a class="header-anchor" href="#su-dung-lenh-nslookup" aria-label="Permalink to &quot;Sử dụng lệnh \`\`\`nslookup\`\`\`&quot;">​</a></h2><p>Dùng để truy vấn DNS (Domain Name System), để lấy ánh xạ tên miền hoặc địa chỉ IP và các bản ghi DNS cụ thể khác.</p><p>Gõ trên prompt hoặc powershell:</p><p><code>nslookup</code></p><p><strong>Lưu ý</strong>: Lệnh này sẽ khởi chạy chế độ tương tác, bạn có thể gõ <code>help</code> để liệt kê các lệnh có sẵn!</p><p>Để truy vấn địa chỉ IP của một tên miền cụ thể, bạn cần đặt <code>type</code> thành bản ghi <code>A</code>, sau đó nhập tên miền mục tiêu:</p><p><code>&gt; type=a</code><code>&gt; www.certifiedhacker.com</code></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&gt; set type=a</span></span>
<span class="line"><span>&gt; www.certifiedhacker.com</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Server:  dns.google</span></span>
<span class="line"><span>Address:  8.8.8.8</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Non-authoritative answer:</span></span>
<span class="line"><span>Name:    certifiedhacker.com</span></span>
<span class="line"><span>Address:  162.241.216.11</span></span>
<span class="line"><span>Aliases:  www.certifiedhacker.com</span></span></code></pre></div><p><strong>Lưu ý</strong>: Môi trường này sử dụng DNS server của Google (8.8.8.8). Để cấu hình DNS server của riêng bạn, chỉ cần gõ <code>server x.x.x.x</code>.</p><p>Hai dòng đầu tiên <strong>dns.google</strong> và <strong>8.8.8.8</strong> cho biết kết quả đã được chuyển đến server này để phân giải tên miền bạn yêu cầu. DNS server của Google không chứa các file zone gốc của tên miền, đây là lý do tại sao nó là <strong>Non-authoritative</strong>.</p><p><strong>Authoritative</strong> là name server có các file nguồn gốc của zone files tên miền. Để lấy Authoritative name server, đặt <code>type</code> thành bản ghi <code>CNAME</code> và truy vấn mục tiêu:</p><p><code>set type=cname</code><code>certifiedhacker.com</code></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&gt; set type=cname</span></span>
<span class="line"><span>&gt; certifiedhacker.com</span></span>
<span class="line"><span>Server:  dns.google</span></span>
<span class="line"><span>Address:  8.8.8.8</span></span>
<span class="line"><span></span></span>
<span class="line"><span>certifiedhacker.com</span></span>
<span class="line"><span>        primary name server = ns1.bluehost.com</span></span>
<span class="line"><span>        responsible mail addr = dnsadmin.box5331.bluehost.com</span></span>
<span class="line"><span>        serial  = 2018011205</span></span>
<span class="line"><span>        refresh = 86400 (1 day)</span></span>
<span class="line"><span>        retry   = 7200 (2 hours)</span></span>
<span class="line"><span>        expire  = 3600000 (41 days 16 hours)</span></span>
<span class="line"><span>        default TTL = 300 (5 mins)</span></span></code></pre></div><p>Truy vấn <code>CNAME</code> được thực hiện trực tiếp với authoritative name server của tên miền.</p><p>Với authoritative name server, bạn có thể xác định địa chỉ IP. Để truy vấn địa chỉ IP, đặt <code>type</code> thành <code>A</code>, sau đó gõ <strong>primary name server</strong> hiển thị trong môi trường lab của bạn, trong trường hợp của tôi: <code>ns1.bluehost.com</code>.</p><p><code>set type=a</code><code>ns1.bluehost.com</code></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&gt; set type=a</span></span>
<span class="line"><span>&gt; ns1.bluehost.com</span></span>
<span class="line"><span>Server:  dns.google</span></span>
<span class="line"><span>Address:  8.8.8.8</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Non-authoritative answer:</span></span>
<span class="line"><span>Name:    ns1.bluehost.com</span></span>
<span class="line"><span>Address:  162.159.24.80</span></span></code></pre></div><p>Tóm lại, <strong>Authoritative name server</strong> lưu trữ các bản ghi liên kết với tên miền tương ứng. Khi có authoritative name server (primary name server) và địa chỉ IP liên kết với nó, kẻ tấn công có thể cố gắng khai thác server, thực hiện các cuộc tấn công như DDoS, chuyển hướng URL, v.v.</p><p><strong>Phân tích cuối cùng:</strong></p><ul><li>Ghi lại tất cả các địa chỉ IP</li><li>Địa chỉ IP của các yêu cầu phản hồi</li><li>Thông tin về TTL</li><li>Tên DNS server và các thông tin DNS khác.</li></ul>`,83)]))}const m=a(i,[["render",c]]);export{g as __pageData,m as default};
